// Slack sends interactivity payloads as form-urlencoded with a single 'payload'
// field containing JSON-encoded data.
const body = $input.first().json.body || $input.first().json;
let payload;
try {
  payload = typeof body.payload === 'string' ? JSON.parse(body.payload) : body.payload;
} catch (e) {
  throw new Error('Failed to parse Slack payload: ' + e.message);
}

const action = (payload.actions || []).find(a => a.action_id === 'bounce_to_consumer');
if (!action) {
  throw new Error('No bounce_to_consumer action in payload');
}

const callerPhone = action.value;
if (!callerPhone) {
  throw new Error('No phone number in action value');
}

function formatTime(iso) {
  const d = new Date(iso);
  return d.toLocaleString('en-US', {
    timeZone: 'America/New_York',
    hour: 'numeric', minute: '2-digit', hour12: true
  }) + ' ET';
}

const nowIso = new Date().toISOString();

return [{
  json: {
    callerPhone: callerPhone,
    userId: payload.user.id,
    userName: payload.user.username || payload.user.name,
    channelId: payload.channel.id,
    messageTs: payload.message.ts,
    originalBlocks: payload.message.blocks || [],
    timestamp: nowIso,
    formattedTime: formatTime(nowIso)
  }
}];

// Update the original Slack message: strip the Bounce button, add a context line
const parsed = $('Parse Action Payload').first().json;
const originalBlocks = parsed.originalBlocks || [];

const updatedBlocks = [];
for (const block of originalBlocks) {
  if (block.type === 'actions') {
    const remaining = (block.elements || []).filter(e => e.action_id !== 'bounce_to_consumer');
    if (remaining.length) {
      updatedBlocks.push({ ...block, elements: remaining });
    }
  } else {
    updatedBlocks.push(block);
  }
}

updatedBlocks.push({
  type: 'context',
  elements: [{
    type: 'mrkdwn',
    text: `✅ Bounced to consumer line by <@${parsed.userId}> at ${parsed.formattedTime}`
  }]
});

return [{
  json: {
    slackBody: JSON.stringify({
      channel: parsed.channelId,
      ts: parsed.messageTs,
      blocks: updatedBlocks,
      text: 'Voicemail bounced to consumer line'
    })
  }
}];
